// gutter_widget.cpp - GutterWidget implementation
//
// Renders line numbers with:
// - Right-aligned text
// - Dynamic width based on line count
// - Current line highlight
// - Virtualized rendering (only visible lines)

#include "gutter_widget.h"
#include "content_widget.h"  // For ContentConfig::LINE_HEIGHT
#include <Windows.h>
#include <d2d1.h>
#include <dwrite.h>
#include <cstdio>
#include <cmath>

// External resources (defined in platform.cpp, accessed via unity build)
extern IDWriteFactory* g_dwrite_factory;
extern IDWriteTextFormat* g_text_format_mono;
extern EventDispatcher g_event_dispatcher;

namespace CodeEditor {

// ============================================================================
// Color Helpers
// ============================================================================

static D2D1_COLOR_F gutter_to_color_f(uint32_t argb) {
    return D2D1::ColorF(
        ((argb >> 16) & 0xFF) / 255.0f,
        ((argb >> 8) & 0xFF) / 255.0f,
        (argb & 0xFF) / 255.0f,
        ((argb >> 24) & 0xFF) / 255.0f
    );
}

// ============================================================================
// LineNumberLayoutCache Implementation
// ============================================================================

IDWriteTextLayout* LineNumberLayoutCache::get(size_t line_num) const {
    if (line_num == 0) return nullptr;
    size_t index = (line_num - 1) % GutterConfig::LAYOUT_CACHE_SIZE;
    const Entry& entry = entries[index];
    if (entry.line_number == line_num) {
        return entry.layout;
    }
    return nullptr;
}

void LineNumberLayoutCache::put(size_t line_num, IDWriteTextLayout* layout) {
    if (line_num == 0 || !layout) return;
    size_t index = (line_num - 1) % GutterConfig::LAYOUT_CACHE_SIZE;
    Entry& entry = entries[index];

    // Release existing layout if it differs (handles both eviction and re-put)
    if (entry.layout && entry.layout != layout) {
        entry.layout->Release();
    }

    entry.line_number = line_num;
    entry.layout = layout;
}

void LineNumberLayoutCache::clear() {
    for (size_t i = 0; i < GutterConfig::LAYOUT_CACHE_SIZE; i++) {
        if (entries[i].layout) {
            entries[i].layout->Release();
            entries[i].layout = nullptr;
        }
        entries[i].line_number = 0;
    }
}

// ============================================================================
// GutterWidget Construction / Destruction
// ============================================================================

GutterWidget::GutterWidget() : Widget() {
    debug_name = "CodeEditor::GutterWidget";
    computed_width_ = GutterConfig::MIN_WIDTH;

    // Make focusable so clicking gutter doesn't clear focus from editor
    // SkipTabStop keeps it out of Tab navigation order
    flags |= WidgetFlags::Focusable | WidgetFlags::SkipTabStop;
}

GutterWidget::~GutterWidget() {
    layout_cache_.clear();
}

// ============================================================================
// Binding
// ============================================================================

void GutterWidget::bind(const LineIndex* index, const float* scroll_y) {
    // Clear layout cache when rebinding (new document)
    if (line_index_ != index) {
        layout_cache_.clear();
    }
    line_index_ = index;
    scroll_y_ = scroll_y;
    set_dirty();
}

void GutterWidget::set_current_line(size_t line_num) {
    if (current_line_ != line_num) {
        current_line_ = line_num;
        set_dirty();
    }
}

// ============================================================================
// Width Calculation
// ============================================================================

void GutterWidget::update_width_for_line_count(size_t line_count) {
    // Calculate number of digits needed
    size_t digits = 1;
    size_t n = line_count;
    while (n >= 10) {
        digits++;
        n /= 10;
    }

    // Minimum 3 digits for visual consistency
    if (digits < 3) digits = 3;

    // Calculate width: padding + digit space + padding
    float width = GutterConfig::PADDING_LEFT
                + (digits * GutterConfig::DIGIT_WIDTH)
                + GutterConfig::PADDING_RIGHT;

    // Enforce minimum
    if (width < GutterConfig::MIN_WIDTH) {
        width = GutterConfig::MIN_WIDTH;
    }

    if (computed_width_ != width) {
        computed_width_ = width;
        layout_cache_.clear();  // Layouts have embedded width, must recreate
        set_dirty();
    }
}

// ============================================================================
// Widget Interface
// ============================================================================

void GutterWidget::measure(const LayoutConstraints& constraints) {
    (void)constraints;

    // Use computed width based on line count
    preferred_width = computed_width_;
    preferred_height = rect.height;  // Fill available height
}

void GutterWidget::layout() {
    // Nothing special needed - rect is set by parent
}

void GutterWidget::render(RenderContext& ctx) {
    if (!line_index_ || !scroll_y_) {
        // Draw empty gutter background
        D2D1_RECT_F bg = {rect.x, rect.y, rect.x + rect.width, rect.y + rect.height};
        ctx.brush->SetColor(gutter_to_color_f(GutterConfig::BACKGROUND_COLOR));
        ctx.target->FillRectangle(bg, ctx.brush);
        return;
    }

    // Clip to widget bounds
    D2D1_RECT_F clip_rect = {rect.x, rect.y, rect.x + rect.width, rect.y + rect.height};
    ctx.push_clip(clip_rect);

    // Background
    ctx.brush->SetColor(gutter_to_color_f(GutterConfig::BACKGROUND_COLOR));
    ctx.target->FillRectangle(clip_rect, ctx.brush);

    // Get visible line range
    float scroll = *scroll_y_;
    size_t first = line_index_->first_visible_line(scroll);
    size_t last = line_index_->last_visible_line(scroll, rect.height);
    size_t total = line_index_->line_count();

    // Clamp to valid range
    if (first < 1) first = 1;
    if (last > total) last = total;

    // Render each visible line number
    for (size_t ln = first; ln <= last; ln++) {
        // Calculate Y position
        float y = rect.y + (ln - 1) * ContentConfig::LINE_HEIGHT - scroll;

        // Skip if outside bounds
        if (y + ContentConfig::LINE_HEIGHT < rect.y) continue;
        if (y > rect.y + rect.height) break;

        // Current line highlight
        if (ln == current_line_) {
            D2D1_RECT_F hl = {rect.x, y, rect.x + rect.width, y + ContentConfig::LINE_HEIGHT};
            ctx.brush->SetColor(gutter_to_color_f(GutterConfig::CURRENT_LINE_BG));
            ctx.target->FillRectangle(hl, ctx.brush);
        }

        // Try to get layout from cache first
        IDWriteTextLayout* layout = layout_cache_.get(ln);

        if (!layout && g_dwrite_factory && g_text_format_mono) {
            // Cache miss - create new layout
            wchar_t num_str[32];
            swprintf_s(num_str, _countof(num_str), L"%zu", ln);

            float text_width = rect.width - GutterConfig::PADDING_RIGHT;
            HRESULT hr = g_dwrite_factory->CreateTextLayout(
                num_str,
                static_cast<UINT32>(wcslen(num_str)),
                g_text_format_mono,
                text_width,
                ContentConfig::LINE_HEIGHT,
                &layout
            );

            if (SUCCEEDED(hr) && layout) {
                layout->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_TRAILING);
                layout_cache_.put(ln, layout);  // Cache takes ownership
            }
        }

        if (layout) {
            ctx.brush->SetColor(gutter_to_color_f(GutterConfig::LINE_NUMBER_COLOR));
            D2D1_POINT_2F text_pos = {rect.x, y};
            ctx.target->DrawTextLayout(text_pos, layout, ctx.brush);
            // Don't release - cache owns the layout
        }
    }

    // Right border
    D2D1_RECT_F border = {
        rect.x + rect.width - 1.0f, rect.y,
        rect.x + rect.width, rect.y + rect.height
    };
    ctx.brush->SetColor(gutter_to_color_f(GutterConfig::BORDER_COLOR));
    ctx.target->FillRectangle(border, ctx.brush);

    ctx.pop_clip();
}

// ============================================================================
// Mouse Event Handling
// ============================================================================

bool GutterWidget::on_mouse_down(float x, float y, int button) {
    (void)x; (void)y; (void)button;
    // Request focus on parent CodeEditorWidget (GutterWidget is focusable to prevent
    // focus being cleared to nullptr, but we want the parent to actually have focus
    // so editor_has_focus(parent) returns true for cursor rendering)
    if (parent) {
        g_event_dispatcher.set_focus(parent);
    }
    // Note: We return false to indicate click was not "consumed" for other purposes
    // (e.g., future line selection), but focus is already set
    return false;
}

// ============================================================================
// Keyboard Event Forwarding
// ============================================================================

bool GutterWidget::on_key_down(int vk, bool ctrl, bool shift, bool alt) {
    // Forward to parent CodeEditorWidget so typing continues even when gutter is focused
    if (parent) {
        return parent->on_key_down(vk, ctrl, shift, alt);
    }
    return false;
}

bool GutterWidget::on_char(wchar_t c) {
    // Forward to parent CodeEditorWidget
    if (parent) {
        return parent->on_char(c);
    }
    return false;
}

} // namespace CodeEditor
